mapper.select:

SELECT product_name
    FROM review_board
    where board_id=#{value}

SELECT category2
FROM review_board
WHERE board_id = #{value}

SELECT COUNT(*) 
FROM master_board m
INNER JOIN review_board r ON m.board_id = r.board_id
WHERE m.board_type = #{type}

    AND r.category1 = #{search.category1}


    AND r.category2 = #{search.category2}

SELECT m.board_id AS boardId, mem.nickname AS nickName, mf.file_path AS memberProfilePath, mf.saved_name AS memberProfileSavedName, m.title AS title, m.content AS content, m.created_at AS createdAt, m.view_cnt AS viewCnt, m.reply_cnt AS replyCnt, bf.saved_name AS savedName, -- C드라이브에서 불러올 때 사용할 저장된 파일명(업로드 파일 수신용) r.product_name AS productName, r.category1, r.category2 FROM member mem INNER JOIN master_board m ON mem.username = m.username INNER JOIN review_board r ON m.board_id = r.board_id LEFT JOIN member_profile mf ON mem.username = mf.username LEFT JOIN board_file bf ON bf.file_id = ( -- 해당 게시글의 파일들 중 가장 첫 번째 파일 ID 하나만 조회하는 서브쿼리 SELECT MIN(file_id) FROM board_file WHERE board_id = m.board_id )
m.board_type = #{type} AND m.deleted = 0
AND r.category1 = #{search.category1}
AND r.category2 = #{search.category2}
ORDER BY m.view_cnt DESC, m.board_id DESC
ORDER BY m.created_at DESC, m.board_id DESC
LIMIT #{pageVO.offset}, #{pageVO.size}
